sql:
SELECT name, location_city
FROM universities
WHERE degree_length = '2 Year';

external_knowledge:
- "lighthouses" metaphorically refers to universities;
- "sunshine state" is a nickname for Florida;
- "beacons of knowledge" refers to the tuition costs (in-state and out-of-state);
- "paths to their portals" refers to the website URLs;
- "helplines to their hearts" refers to the phone numbers;
- "keepers" metaphorically refers to the users who access the data (administrators or staff members);
- "2023" specifies the year for which the data is being retrieved.

sql:
SELECT COUNT(*) 
FROM total_costs
WHERE in_state_total > (SELECT AVG(in_state_total) FROM total_costs);

SELECT name 
FROM universities
WHERE enrollment = (SELECT MAX(enrollment) FROM universities);

SELECT u.name, tc.in_state_tuition 
FROM universities u 
INNER JOIN tuition_costs tc ON u.university_id = tc.university_id 
WHERE tc.in_state_tuition = (
    SELECT MAX(in_state_tuition) FROM tuition_costs
);
